typedef enum objc_async_completion_status {
    OBJC_ASYNC_COMPLETION_SUCCESS = 0,
    OBJC_ASYNC_COMPLETION_ERROR = 1,
    OBJC_ASYNC_COMPLETION_CANCELLED = 2
} objc_async_completion_status_t;

typedef void (*INTC04Completion)(void * _Nullable context,
                                 objc_async_completion_status_t status,
                                 id _Nullable result,
                                 id<Error> _Nullable error);

id intc04_lookup(int token) async;
void intc04_lookup_async_c(int token,
                           void * _Nullable context,
                           INTC04Completion _Nonnull completion);

int intc04_validate_boundary(objc_async_completion_status_t status,
                             id<Error> _Nullable error) {
    if (status == OBJC_ASYNC_COMPLETION_SUCCESS) {
        return error == nil ? 1 : 0;
    }
    if (status == OBJC_ASYNC_COMPLETION_CANCELLED) {
        return error != nil ? 1 : 0;
    }
    return 0;
}
